import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';

// Importación de Componentes
import Header from './components/Header';
import Home from './components/Home';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import GestionOfertas from './components/GestionOfertas';

function App() {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [userRole, setUserRole] = useState(null); // 'cliente' o 'vendedor'

  // 1. Persistencia de Sesión: Al cargar la página, revisamos si ya estaba logueado
  useEffect(() => {
    const role = localStorage.getItem('user-role');
    const token = localStorage.getItem('token-falso');
    if (token && role) {
      setIsLoggedIn(true);
      setUserRole(role);
    }
  }, []);

  // 2. Función para Cerrar Sesión (la pasamos al Header)
  const cerrarSesion = () => {
    localStorage.removeItem('token-falso');
    localStorage.removeItem('user-role');
    setIsLoggedIn(false);
    setUserRole(null);
    window.location.href = '/login'; // Redirigir al login al salir
  };

  return (
    <Router>
      {/* El Header recibe el estado y la función de cierre */}
      <Header 
        isLoggedIn={isLoggedIn} 
        userRole={userRole} 
        cerrarSesion={cerrarSesion} 
      />

      <main style={{ minHeight: 'calc(100vh - 75px)' }}>
        <Routes>
          {/* RUTA PÚBLICA: Home (Buscador para clientes) */}
          <Route path="/" element={<Home />} />

          {/* LOGIN: Recibe funciones para actualizar el estado global */}
          <Route path="/login" element={
            <Login setIsLoggedIn={setIsLoggedIn} setUserRole={setUserRole} />
          } />

          {/* RUTAS PROTEGIDAS PARA VENDEDORES (Panel y Carga de Ofertas) */}
          <Route 
            path="/dashboard" 
            element={isLoggedIn && userRole === 'vendedor' ? <Dashboard /> : <Navigate to="/login" />} 
          />

          <Route 
            path="/ofertas/:id" 
            element={isLoggedIn && userRole === 'vendedor' ? <GestionOfertas /> : <Navigate to="/login" />} 
          />

          {/* REDIRECCIÓN POR DEFECTO: Si la ruta no existe, al Home */}
          <Route path="*" element={<Navigate to="/" />} />
        </Routes>
      </main>
    </Router>
  );
}

export default App;
